import React, { useCallback, useMemo } from 'react';
import { SearchInput, type SearchInputConfig } from '@linm-soft-org/linm-web-common-components';
import { useCatalogSearchConfig } from '../../catalog/catalogUiSchema/useCatalogSearchConfig';
import { hrEndpoint } from '../../../services/ns/endpoint';
import type { HrEmployeeGroupDto } from '../../../services/ns/models';
import { HR_EMPLOYEE_GROUPS_CATALOG_KIND } from './EmployeeGroupLookupField';

const MAX_PARENT_SLOT = 3;

type Props = {
  parentId: string;
  parentCode?: string;
  parentName?: string;
  disabled?: boolean;
  onChange: (parent: HrEmployeeGroupDto) => void;
  onClear: () => void;
  testId?: string;
};

function buildParentSearchConfig(
  search: (params: {
    search?: string;
    page?: number;
    pageSize?: number;
  }) => ReturnType<typeof hrEndpoint.getEmployeeGroups>,
): SearchInputConfig<HrEmployeeGroupDto> {
  return {
    api: {
      getItemKey: item => item.id,
      search: async ({ search: term, page, pageSize }) => {
        const data = await search({ search: term, page, pageSize });
        const size = data.pageSize || 20;
        const totalPages = Math.max(1, Math.ceil(data.totalCount / size));
        return { items: data.items, page: data.page, totalPages };
      },
    },
    display: {
      getPrimaryDisplay: item => item.code,
      getSecondaryDisplay: item => item.name,
    },
    columns: [
      { key: 'code', variant: 'badge', width: '7rem', render: item => item.code || '—' },
      { key: 'name', variant: 'primary', render: item => item.name || '—' },
      { key: 'slot', variant: 'meta', width: '4rem', render: item => String(item.slot) },
    ],
    header: {
      columns: [
        { key: 'code', label: 'Mã nhóm' },
        { key: 'name', label: 'Tên nhóm' },
        { key: 'slot', label: 'Cấp' },
      ],
    },
    dropdownMatch: 'row',
    dropdownMinWidth: '24rem',
    texts: { empty: 'Không có nhóm cha phù hợp' },
  };
}

/** Lookup nhóm cha — chỉ cấp 1–3 (có thể làm parent). */
export const HrEmployeeGroupParentLookupField: React.FC<Props> = ({
  parentId,
  parentCode,
  parentName,
  disabled,
  onChange,
  onClear,
  testId,
}) => {
  const search = useCallback(
    (params: { search?: string; page?: number; pageSize?: number }) =>
      hrEndpoint.getEmployeeGroups({
        search: params.search,
        page: params.page,
        pageSize: params.pageSize,
        isActive: true,
        maxSlot: MAX_PARENT_SLOT,
      }),
    [],
  );

  const { config: schemaConfig, loading } = useCatalogSearchConfig<HrEmployeeGroupDto>(
    HR_EMPLOYEE_GROUPS_CATALOG_KIND,
    search,
    item => item.id,
    {
      getPrimaryDisplay: item => item.code,
      getSecondaryDisplay: item => item.name,
    },
  );

  const fallbackConfig = useMemo(() => buildParentSearchConfig(search), [search]);
  const effectiveConfig = schemaConfig ?? fallbackConfig;

  const primaryDisplay = useMemo(() => {
    if (!parentId) return '';
    if (parentCode && parentName) return `${parentCode} — ${parentName}`;
    return parentName ?? parentCode ?? '';
  }, [parentId, parentCode, parentName]);

  return (
    <SearchInput
      config={effectiveConfig}
      value={parentId}
      primaryDisplay={primaryDisplay}
      onChange={onChange}
      onClear={onClear}
      disabled={disabled || loading}
      showLabel={false}
      showSecondaryInput={false}
      placeholder={loading ? 'Đang tải...' : 'Chọn nhóm cha (tùy chọn)...'}
      data-testid={testId}
    />
  );
};

export function computeChildSlot(parentSlot: number | undefined): number {
  if (!parentSlot || parentSlot < 1) return 1;
  return Math.min(parentSlot + 1, 4);
}
